const items = $input.all();
if (!items || items.length === 0 || !items[0].json.id) {
  return [];
}
return items;

const doc = $json;
const content = doc.content || '';
const title = doc.title || 'Untitled';
const docType = doc.doc_type || 'document';

if (!content || content.length < 50) {
  return [{ json: { doc_id: doc.id, title, error: 'Content too short or empty', chunks: [] } }];
}

// Split into ~1000 char chunks with 200 char overlap
const CHUNK_SIZE = 1000;
const OVERLAP = 200;
const chunks = [];
let start = 0;
let chunkIdx = 0;

while (start < content.length) {
  const end = Math.min(start + CHUNK_SIZE, content.length);
  let chunk = content.substring(start, end);

  // Try to break at sentence boundary
  if (end < content.length) {
    const lastPeriod = chunk.lastIndexOf('.');
    const lastNewline = chunk.lastIndexOf('\n');
    const breakPoint = Math.max(lastPeriod, lastNewline);
    if (breakPoint > CHUNK_SIZE * 0.5) {
      chunk = chunk.substring(0, breakPoint + 1);
    }
  }

  chunks.push({
    chunk_index: chunkIdx,
    text: chunk.trim(),
    doc_id: doc.id,
    title: title,
    doc_type: docType,
    opp_id: doc.opp_id || null,
    metadata: doc.metadata || {}
  });

  chunkIdx++;
  start = start + chunk.length - OVERLAP;
  if (start <= 0 && chunkIdx > 0) break;
}

return [{ json: { doc_id: doc.id, title, chunk_count: chunks.length, chunks } }];

