={{ (function() {
  const chunks = $('Chunk Document').first().json.chunks || [];
  const summary = $input.first().json.content ? $input.first().json.content[0].text : '';
  const docId = $('Chunk Document').first().json.doc_id;
  const title = $('Chunk Document').first().json.title;
  const values = [];

  // Insert summary as main doc vector
  values.push('doc_auto_index');
  values.push('auto-' + docId);
  values.push(title);
  values.push(summary.substring(0, 2000));
  values.push(JSON.stringify({ doc_id: docId, chunk_count: chunks.length, auto_indexed: true }));

  return values;
})() }}

